      MatchedAnd2
          ? ConstantRange(*C2, *C2 - *Mask2)
          : ConstantRange::makeExactICmpRegion(
                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
  if (Offset2)
    CR2 = CR2.subtract(*Offset2);

  // Check for subset/superset relationships.
  // For AND: if one (inverse) range contains the other, the contained comparison
  // is implied by the containing comparison, so return the contained one.
